import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"Starten des Spiels","description":"Lerne, wie du die verschiedenen Startprofile verwendest, um deine Mods in einer Live-Spielumgebung zu starten und zu debuggen.","frontmatter":{"title":"Starten des Spiels","description":"Lerne, wie du die verschiedenen Startprofile verwendest, um deine Mods in einer Live-Spielumgebung zu starten und zu debuggen.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"de_de/1.20.4/develop/getting-started/launching-the-game.md","filePath":"versions/1.20.4/translated/de_de/develop/getting-started/launching-the-game.md","lastUpdated":1739538073000}`);var c={name:`de_de/1.20.4/develop/getting-started/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Starten des Spiels <a class="header-anchor" href="#h1" aria-label="Permalink to “Starten des Spiels”">​</a></h1><p>Fabric Loom bietet eine Vielzahl von Startprofilen, die dir helfen, deine Mods in einer Live-Spielumgebung zu starten und zu debuggen. Dieser Leitfaden behandelt die verschiedenen Startprofile und wie man sie zum Debuggen und Testen der Mods verwendet.</p><h2 id="startprofile" tabindex="-1">Startprofile <a class="header-anchor" href="#startprofile" aria-label="Permalink to “Startprofile”">​</a></h2><p>Wenn du IntelliJ IDEA verwendest, findest du die Startprofile in der oberen rechten Ecke des Fensters. Klicke auf das Dropdown-Menü, um die verfügbaren Startprofile anzuzeigen.</p><p>Es sollte ein Client- und ein Serverprofil geben, mit der Möglichkeit, es entweder normal oder im Debug-Modus auszuführen:</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="Startprofile" loading="lazy"></p><h2 id="gradle-aufgaben" tabindex="-1">Gradle Aufgaben <a class="header-anchor" href="#gradle-aufgaben" aria-label="Permalink to “Gradle Aufgaben”">​</a></h2><p>Wenn du die Kommandozeile verwendest, kannst du die folgenden Gradle-Befehle verwenden, um das Spiel zu starten:</p><ul><li><code>./gradlew runClient</code> - Startet das Spiel im Client-Modus.</li><li><code>./gradlew runServer</code> - Startet das Spiel im Server-Modus.</li></ul><p>Das einzige Problem bei diesem Ansatz ist, dass Sie Ihren Code nicht einfach debuggen können. Wenn du deinen Code debuggen willst, musst du die Startprofile in IntelliJ IDEA oder über die Gradle-Integration deiner IDE verwenden.</p><h2 id="hotswapping-von-klassen" tabindex="-1">Hotswapping von Klassen <a class="header-anchor" href="#hotswapping-von-klassen" aria-label="Permalink to “Hotswapping von Klassen”">​</a></h2><p>Wenn du das Spiel im Debug-Modus ausführst, kannst du deine Klassen per Hotswap austauschen, ohne das Spiel neu zu starten. Dies ist nützlich, um Änderungen an deinem Code schnell zu testen.</p><p>Du bist aber immer noch ziemlich eingeschränkt:</p><ul><li>Du kannst keine Methoden hinzufügen oder entfernen</li><li>Du kannst die Methodenparameter nicht ändern</li><li>Du kannst keine Attribute hinzufügen oder entfernen</li></ul><h2 id="hotswapping-von-mixins" tabindex="-1">Hotswapping von Mixins <a class="header-anchor" href="#hotswapping-von-mixins" aria-label="Permalink to “Hotswapping von Mixins”">​</a></h2><p>Wenn du Mixins verwendest, kannst du deine Mixin-Klassen per Hotswap austauschen, ohne das Spiel neu zu starten. Dies ist nützlich, um Änderungen an deinen Mixins schnell zu testen.</p><p>Hierzu musst du allerdings den Mixin-Java-Agent installieren, damit das funktioniert.</p><h3 id="_1-finde-die-jar-der-mixin-bibliothek" tabindex="-1">1. Finde die JAR der Mixin Bibliothek <a class="header-anchor" href="#_1-finde-die-jar-der-mixin-bibliothek" aria-label="Permalink to “1. Finde die JAR der Mixin Bibliothek”">​</a></h3><p>In IntelliJ IDEA findest du die Mixin-Bibliothek JAR im Abschnitt &quot;External Libraries&quot; des Abschnitts &quot;Project&quot;:</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Mixin Bibliothek" loading="lazy"></p><p>Für den nächsten Schritt musst du den &quot;Absolute Path&quot; (Absoluten Pfad) der JAR-Datei kopieren.</p><h3 id="_2-fuge-das-vm-argument-javaagent-hinzu" tabindex="-1">2. Füge das VM-Argument <code>-javaagent</code> hinzu <a class="header-anchor" href="#_2-fuge-das-vm-argument-javaagent-hinzu" aria-label="Permalink to “2. Füge das VM-Argument -javaagent hinzu”">​</a></h3><p>Füge in deiner &quot;Minecraft Client&quot;- und/oder &quot;Minecraft Server&quot;-Ausführungskonfiguration Folgendes zur Option VM-Argumente hinzu:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;Pfad zur Mixin-Bibliothek JAR hier&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="Bildschirmfoto der VM-Argumente" loading="lazy"></p><p>Jetzt solltest du in der Lage sein, den Inhalt deiner Mixin-Methoden während des Debuggens zu ändern und die Änderungen wirksam werden zu lassen, ohne das Spiel neu zu starten.</p>`,26)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};